            name="skill_result",
            display_name="Skill 실행 결과",
            method="run_skill",
            types=["Data"],
            tool_mode=True,
        ),
        Output(
            name="skill_message",
            display_name="하위 Flow 응답",
            method="run_skill_message",
            types=["Message"],
            tool_mode=False,
        ),
    ]

