        self.status = (
            f"{status_label} · 입력 {result['input_count']}개 · 변환 {result['encoded_count']}개 · "
            f"제외 {result['rejected_count']}개 · 오류 {result['error_count']}건 · "
            f"출력 {format_label} · 처리 방식 {policy_label}"
        )
        return Data(data=result)

