from lfx.schema.data import Data


def normalize_business_profile(business_request_value: Any, llm_profile_response: Any = "") -> dict[str, Any]:
    """Agent/LLM 구조화 응답을 검증하고, 없으면 업무 설명 기반 fallback 프로필을 만듭니다."""
    payload = _payload(business_request_value)
    request = _dict(payload.get("business_request"))
    work_description = str(request.get("work_description") or "").strip()

    parsed = _parse_json_like(llm_profile_response)
    profile = _dict(parsed.get("business_profile")) if isinstance(parsed, dict) else {}
    source = "llm" if profile else "fallback"
    if not profile:
        profile = _fallback_profile(work_description)

    normalized = _normalize_profile(profile, work_description)
    issues = _validation_issues(normalized)
    trace = _dict(payload.get("trace"))
    warnings = list(trace.get("warnings") or [])
    warnings.extend(issues)

    return {
        **payload,
        "workflow_profile": normalized,
        "profile_validation": {
            "valid": len(issues) == 0,
            "issues": issues,
            "source": source,
            "normalized_at": _now_iso(),
        },
        "trace": {
            **trace,
            "warnings": warnings,
        },
    }


def _fallback_profile(text: str) -> dict[str, Any]:
    sentences = _sentences(text)
    steps = []
    for index, sentence in enumerate(sentences[:8], 1):
        steps.append(
            {
                "step_id": f"S{index}",
                "title": _short_title(sentence, f"현재 업무 {index}"),
                "description": sentence,
                "actor": "업무 담당자",
                "systems": _keyword_hits(sentence, ["엑셀", "메일", "ERP", "MES", "SQL", "DB", "대시보드", "Slack", "Teams"]),
                "data": _keyword_hits(sentence, ["생산", "불량", "재공", "품질", "정비", "작업 이력", "고객", "주문", "재고"]),
            }
        )

    if not steps:
        steps = [
            {
                "step_id": "S1",
                "title": "업무 설명 확인",
                "description": "입력된 업무 설명이 부족하여 기본 단계만 생성했습니다.",
                "actor": "업무 담당자",
                "systems": [],
                "data": [],
            }
        ]

    return {
        "business_goal": _infer_goal(text),
        "current_flow": steps,
        "data_and_systems": _infer_data_systems(text, steps),
        "constraints": _infer_constraints(text),
        "desired_outputs": _infer_outputs(text),
        "risk_signals": _infer_risks(text),
        "assumptions": ["Agent/LLM 구조화 응답이 없어 입력 문장 기반 fallback으로 구성했습니다."],
        "open_questions": [],
    }


def _normalize_profile(profile: dict[str, Any], raw_text: str) -> dict[str, Any]:
    current_flow = []
    for index, item in enumerate(_as_list(profile.get("current_flow")), 1):
        step = _dict(item)
        current_flow.append(
            {
                "step_id": str(step.get("step_id") or f"S{index}"),
                "title": str(step.get("title") or f"현재 업무 {index}").strip(),
                "description": str(step.get("description") or "").strip(),
                "actor": str(step.get("actor") or "업무 담당자").strip(),
                "systems": _string_list(step.get("systems")),
                "data": _string_list(step.get("data")),
            }
        )

    if not current_flow:
        current_flow = _fallback_profile(raw_text)["current_flow"]

    return {
        "business_goal": str(profile.get("business_goal") or _infer_goal(raw_text)).strip(),
        "current_flow": current_flow,
        "data_and_systems": _normalize_name_role_items(profile.get("data_and_systems")),
        "constraints": _string_list(profile.get("constraints")) or _infer_constraints(raw_text),
        "desired_outputs": _string_list(profile.get("desired_outputs")) or _infer_outputs(raw_text),
        "risk_signals": _string_list(profile.get("risk_signals")) or _infer_risks(raw_text),
        "assumptions": _string_list(profile.get("assumptions")),
        "open_questions": _string_list(profile.get("open_questions")),
        "raw_work_description": raw_text,
    }


def _validation_issues(profile: dict[str, Any]) -> list[str]:
    issues = []
    if not profile.get("business_goal"):
        issues.append("업무 목적이 비어 있습니다.")
    if not profile.get("current_flow"):
        issues.append("현재 업무 단계가 비어 있습니다.")
    if len(str(profile.get("raw_work_description") or "")) < 20:
        issues.append("업무 설명이 짧아 추천 정확도가 낮을 수 있습니다.")
    return issues


def _parse_json_like(value: Any) -> Any:
    if isinstance(value, (dict, list)):
        return value
    text = _extract_text(value).strip()
    if not text:
        return None
    if "```" in text:
        for block in re.findall(r"```(?:json)?\s*(.*?)```", text, flags=re.I | re.S):
            parsed = _parse_json_like(block)
            if parsed is not None:
                return parsed
    try:
        return json.loads(text)
    except Exception:
        pass
    match = re.search(r"(\{.*\}|\[.*\])", text, flags=re.S)
    if match:
        try:
            return json.loads(match.group(1))
        except Exception:
            return None
    return None


def _extract_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        return value
    if hasattr(value, "text"):
        return str(value.text)
    if hasattr(value, "data"):
        return _extract_text(value.data)
    if isinstance(value, dict):
        for key in ("text", "message", "content", "input_value"):
            if key in value:
                return _extract_text(value[key])
        return json.dumps(value, ensure_ascii=False)
    return str(value)


def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


def _as_list(value: Any) -> list[Any]:
    if isinstance(value, list):
        return value
    if value in (None, "", {}):
        return []
    return [value]


def _string_list(value: Any, limit: int = 12) -> list[str]:
    result = []
    seen = set()
    for item in _as_list(value):
        text = str(item or "").strip()
        if text and text not in seen:
            seen.add(text)
            result.append(text)
        if len(result) >= limit:
            break
    return result


def _sentences(text: str) -> list[str]:
    parts = re.split(r"[\n\r]+|(?<=[.!?。])\s+|(?<=다\.)\s*", text)
    result = [part.strip(" -\t") for part in parts if part.strip(" -\t")]
    if len(result) <= 1:
        result = [part.strip() for part in re.split(r"[.;]", text) if part.strip()]
    return result


def _short_title(sentence: str, fallback: str) -> str:
    text = re.sub(r"\s+", " ", sentence).strip()
    return text[:28] + ("..." if len(text) > 28 else "") if text else fallback


def _keyword_hits(text: str, keywords: list[str]) -> list[str]:
    lowered = text.lower()
    return [key for key in keywords if key.lower() in lowered]


def _infer_goal(text: str) -> str:
    if any(key in text for key in ["위험", "이상", "불량", "품질"]):
        return "업무 데이터를 확인해 위험 징후를 빠르게 파악하고 필요한 조치를 준비합니다."
    if any(key in text for key in ["보고", "공유", "회의"]):
        return "반복 보고 업무를 정리하고 필요한 산출물을 안정적으로 준비합니다."
    return "반복 업무를 구조화하고 AI Agent 적용 가능 영역을 찾습니다."


def _infer_data_systems(text: str, steps: list[dict[str, Any]]) -> list[dict[str, str]]:
    names = set()
    for step in steps:
        names.update(step.get("systems") or [])
        names.update(step.get("data") or [])
    if not names:
        names.update(_keyword_hits(text, ["엑셀", "메일", "ERP", "MES", "DB", "생산 데이터", "품질 데이터"]))
    return [{"name": name, "role": "업무 설명에서 언급된 데이터 또는 시스템"} for name in sorted(names)]


def _infer_constraints(text: str) -> list[str]:
    constraints = []
    if any(key in text for key in ["자동 발송하지", "사람이 확인", "승인", "검토"]):
        constraints.append("중요 작업은 사람 검토 후 실행해야 합니다.")
    if any(key in text for key in ["개인정보", "보안", "민감"]):
        constraints.append("민감 정보와 접근 권한을 통제해야 합니다.")
    return constraints


def _infer_outputs(text: str) -> list[str]:
    outputs = []
    for key in ["보고서", "대시보드", "메일 초안", "알림", "리스트", "요약"]:
        if key in text:
            outputs.append(key)
    return outputs or ["업무 개선 설계서", "현재/개선 업무 Flow"]


def _infer_risks(text: str) -> list[str]:
    risks = []
    if any(key in text for key in ["메일", "발송", "공유", "알림"]):
        risks.append("외부 또는 타인에게 전달되는 커뮤니케이션")
    if any(key in text for key in ["수정", "등록", "삭제", "업데이트", "승인"]):
        risks.append("원본 시스템 변경 가능 작업")
    if any(key in text for key in ["개인정보", "고객", "민감", "보안"]):
        risks.append("민감 정보 처리")
    return risks


def _normalize_name_role_items(value: Any) -> list[dict[str, str]]:
    result = []
    for item in _as_list(value):
        if isinstance(item, dict):
            name = str(item.get("name") or item.get("title") or "").strip()
            role = str(item.get("role") or item.get("description") or "").strip()
        else:
            name = str(item or "").strip()
            role = ""
        if name:
            result.append({"name": name, "role": role or "업무에서 사용하는 데이터 또는 시스템"})
    return result


def _now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()


class BusinessProfileNormalizer(Component):
    display_name = "02 업무 구조화 결과 정리"
    description = "Agent/LLM 구조화 응답을 검증해 표준 업무 프로필로 정리합니다. 응답이 없으면 기본 추정값을 만듭니다."
    icon = "ListChecks"
    inputs = [
        DataInput(name="business_request", display_name="업무 요청", required=True),
        MessageTextInput(name="llm_profile_response", display_name="Agent/LLM 구조화 응답", required=False),
    ]
    outputs = [Output(name="business_profile", display_name="업무 구조화 결과", method="build_payload")]

    def build_payload(self) -> Data:
        result = normalize_business_profile(
            getattr(self, "business_request", None),
            getattr(self, "llm_profile_response", ""),
        )
        validation = result.get("profile_validation", {})
        profile = result.get("workflow_profile", {})
        self.status = {
            "처리 방식": validation.get("source"),
            "현재 단계 수": len(profile.get("current_flow", [])),
            "검증 상태": "정상" if validation.get("valid") else "확인 필요",
        }
        return Data(data=result)

from __future__ import annotations

"""04 Agent design prompt variables.

Standalone Langflow component: it intentionally imports no sibling module.  The
component gives the LLM a graph contract, while the following normalizer remains
the final authority for IDs, edges, change states, and safe fallback output.
"""

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.message import Message


NODE_TYPES = ["start", "process", "decision", "merge", "human_review", "end"]
CHANGE_STATES = ["unchanged", "modified", "added", "human_review", "removed"]


def build_agent_design_template_variables(catalog_context_value: Any) -> dict[str, str]:
    payload = _payload(catalog_context_value)
    context = _dict(payload.get("catalog_context"))
    profile = _dict(context.get("business_profile")) or _dict(payload.get("workflow_profile"))
    items = _list(context.get("ranked_catalog_items"))
    trace = _dict(context.get("recommendation_trace"))

    schema = {
        "report_title": "string",
        "executive_summary": "string",
        "flow_visualization": {
            "before": {
                "nodes": [
                    {
                        "node_id": "before_step_id",
                        "comparison_key": "stable_business_step_key",
                        "label": "string",
                        "description": "string",
                        "actor": "string",
                        "node_type": NODE_TYPES,
                        "change_state": CHANGE_STATES,
                        "recommended_asset_ids": ["catalog canonical_key only"],
                        "improvement_detail_id": "string or empty",
                    }
                ],
                "edges": [
                    {
                        "edge_id": "string",
                        "source": "existing node_id",
                        "target": "existing node_id",
                        "branch_label": "required on decision outgoing edges",
                        "condition": "required on decision outgoing edges",
                        "change_state": CHANGE_STATES,
                    }
                ],
            },
            "after": {"nodes": ["same node schema"], "edges": ["same edge schema"]},
            "change_map": [
                {
                    "comparison_key": "string",
                    "before_node_id": "string or empty",
                    "after_node_id": "string or empty",
                    "change_state": CHANGE_STATES,
                    "summary": "string",
                }
            ],
        },
        "improvement_details": [
            {
                "improvement_detail_id": "string",
                "title": "string",
                "why_change": "string",
                "how_to_improve": "string",
                "recommended_asset_ids": ["catalog canonical_key only"],
                "connection_guidance": ["specific node and port wiring"],
                "acceptance_checks": ["observable test"],
                "human_review": "string",
                "recommendation_trace_ids": ["trace id"],
            }
        ],
        "recommended_capabilities": [
            {
                "catalog_id": "canonical_key from supplied catalog only",
                "title": "string",
                "why_recommended": "string",
                "applies_to_steps": ["comparison_key"],
                "building_blocks": ["string"],
                "source_links": ["string"],
                "risk_level": "low|medium|high",
                "human_review_required": "boolean",
            }
        ],
        "implementation_roadmap": [
            {"phase": "string", "goal": "string", "tasks": ["string"], "success_check": "string"}
        ],
        "risk_controls": [
            {"risk": "string", "control": "string", "human_checkpoint": "string"}
        ],
        "assumptions": ["string"],
        "questions_to_confirm": ["string"],
        "unverified_suggestions": ["catalog 밖의 아이디어만 분리"],
    }

    instructions = """
업무의 현재 상태와 개선 후 상태를 카드 목록이 아닌 두 개의 방향성 있는 Flow Chart로 설계하세요.

필수 규칙:
1. before와 after 각각 start, end node와 유효한 edge를 포함합니다.
2. 조건 판단은 decision node로 만들고, decision에서 나가는 모든 edge에 branch_label과 condition을 씁니다.
3. 분기 경로가 다시 합쳐지면 merge node를 명시합니다.
4. BEFORE/AFTER의 같은 업무 단계에는 같은 comparison_key를 씁니다.
5. AFTER의 변경 node는 modified, added, human_review 중 하나를 사용하고 improvement_detail_id를 연결합니다.
6. BEFORE에서 사라지는 수작업은 removed로 표시합니다. 유지 단계는 unchanged입니다.
7. 추천 자산 ID는 제공된 catalog_items의 canonical_key만 사용합니다. 없는 기능은 unverified_suggestions에만 씁니다.
8. 외부 발송, 승인, 시스템 쓰기/삭제에는 human_review node와 risk control을 둡니다.
9. 각 improvement detail에는 왜 바꾸는지, 구체적 구현 방법, 연결 순서, 성공 확인 기준을 씁니다.
10. HTML/CSS/JavaScript나 좌표를 생성하지 말고 JSON object만 반환합니다.
11. 모르는 내용은 assumptions 또는 questions_to_confirm에 두고 사실처럼 단정하지 않습니다.
""".strip()

    return {
        "business_profile_json": _json(profile),
        "catalog_items_json": _json(items),
        "recommendation_trace_json": _json(trace),
        "design_instructions": instructions,
        "design_output_schema": _json(schema),
    }


def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str):
        try:
            parsed = json.loads(text)
        except Exception:
            return {}
        return deepcopy(parsed) if isinstance(parsed, dict) else {}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    return deepcopy(value) if isinstance(value, list) else []


def _json(value: Any) -> str:
    return json.dumps(value, ensure_ascii=False, indent=2, default=str)


class AgentDesignPromptBuilder(Component):
    display_name = "04 AI Agent 설계 프롬프트 변수 준비"
    description = "업무 구조와 카탈로그를 BEFORE/AFTER graph JSON 설계용 Prompt 변수로 변환합니다."
    icon = "Workflow"
    inputs = [DataInput(name="catalog_context", display_name="추천 컨텍스트", required=True)]
    outputs = [
        Output(name="business_profile_json", display_name="업무 프로필 JSON", method="build_business_profile_json", types=["Message"], group_outputs=True),
        Output(name="catalog_items_json", display_name="추천 카탈로그 JSON", method="build_catalog_items_json", types=["Message"], group_outputs=True),
        Output(name="recommendation_trace_json", display_name="추천 근거 JSON", method="build_recommendation_trace_json", types=["Message"], group_outputs=True),
        Output(name="design_instructions", display_name="설계 지침", method="build_design_instructions", types=["Message"], group_outputs=True),
        Output(name="design_output_schema", display_name="출력 스키마 JSON", method="build_design_output_schema", types=["Message"], group_outputs=True),
    ]

    def _variables(self) -> dict[str, str]:
        cached = getattr(self, "_cached_variables", None)
        if isinstance(cached, dict):
            return cached
        result = build_agent_design_template_variables(getattr(self, "catalog_context", None))
        self._cached_variables = result
        self.status = {"카탈로그 항목": len(json.loads(result["catalog_items_json"])), "출력 방식": "BEFORE/AFTER graph JSON"}
        return result

    def build_business_profile_json(self) -> Message:
        return Message(text=self._variables()["business_profile_json"])

    def build_catalog_items_json(self) -> Message:
        return Message(text=self._variables()["catalog_items_json"])

    def build_recommendation_trace_json(self) -> Message:
        return Message(text=self._variables()["recommendation_trace_json"])

    def build_design_instructions(self) -> Message:
        return Message(text=self._variables()["design_instructions"])

    def build_design_output_schema(self) -> Message:
        return Message(text=self._variables()["design_output_schema"])

